import java.io.File;
import java.io.FileReader;
import java.io.IOException;

public class PathTraversalSecureCode {

    public static void main(String[] args) {
        String userInput = "../secret.txt";
        String baseDirectory = "/var/www/html/public/";

        File requestedFile = new File(baseDirectory + userInput);

        if (!requestedFile.getAbsolutePath().startsWith(new File(baseDirectory).getAbsolutePath())) {
            System.out.println("Invalid file path");
            return;
        }

        try (FileReader reader = new FileReader(requestedFile)) {
            int data;
            while ((data = reader.read()) != -1) {
                System.out.print((char) data);
            }
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

